mapper.select:
SELECT s.STOCK_ID AS stockId, s.PLANT_CD AS plantCd, s.WAREHOUSE_CD AS warehouseCd, s.LOCATION_CD AS locationCd, s.ITEM_CD AS itemCd, i.ITEM_NM AS itemNm, s.LOT_NO AS lotNo, s.STOCK_QTY AS stockQty, s.RESERVED_QTY AS reservedQty, s.AVAILABLE_QTY AS availableQty, s.UNIT AS unit, s.STOCK_STATUS AS stockStatus, s.EXPIRE_DT AS expireDt, s.REG_DTM AS regDtm FROM INV_STOCK s LEFT JOIN MST_ITEM i ON s.ITEM_CD = i.ITEM_CD WHERE 1 = 1
AND s.PLANT_CD = #{plantCd}
AND s.WAREHOUSE_CD = #{warehouseCd}
AND s.ITEM_CD = #{itemCd}
AND s.LOT_NO = #{lotNo}
AND s.STOCK_STATUS = #{stockStatus}
ORDER BY s.ITEM_CD ASC, s.LOT_NO ASC

SELECT s.STOCK_ID AS stockId, s.PLANT_CD AS plantCd, s.WAREHOUSE_CD AS warehouseCd, s.LOCATION_CD AS locationCd, s.ITEM_CD AS itemCd, i.ITEM_NM AS itemNm, s.LOT_NO AS lotNo, s.STOCK_QTY AS stockQty, s.RESERVED_QTY AS reservedQty, s.AVAILABLE_QTY AS availableQty, s.UNIT AS unit, s.STOCK_STATUS AS stockStatus, s.EXPIRE_DT AS expireDt, s.REG_DTM AS regDtm FROM INV_STOCK s LEFT JOIN MST_ITEM i ON s.ITEM_CD = i.ITEM_CD WHERE 1 = 1
AND s.PLANT_CD = #{plantCd}
AND s.WAREHOUSE_CD = #{warehouseCd}
AND s.ITEM_CD = #{itemCd}
AND s.LOT_NO = #{lotNo}
AND s.STOCK_STATUS = #{stockStatus}
ORDER BY s.ITEM_CD ASC, s.LOT_NO ASC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM INV_STOCK s
WHERE 1 = 1

    AND s.PLANT_CD = #{plantCd}


    AND s.WAREHOUSE_CD = #{warehouseCd}


    AND s.ITEM_CD = #{itemCd}


    AND s.LOT_NO = #{lotNo}


    AND s.STOCK_STATUS = #{stockStatus}
